import { Component, inject, signal, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { IsActiveMatchOptions, RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { AcademiaService } from '../../../core/services/academia.service';

interface NavItem {
  label: string;
  rota: string;
  icone: string;
  linkOptions: IsActiveMatchOptions;
  roles?: string[];
}

@Component({
  selector: 'app-sidebar',
  standalone: true,
  imports: [CommonModule, RouterLink, RouterLinkActive],
  templateUrl: './sidebar.component.html',
  styleUrls: ['./sidebar.component.css'],
})
export class SidebarComponent implements OnInit {
  readonly authService = inject(AuthService);
  private readonly academiaService = inject(AcademiaService);

  readonly academiaName = signal('Academia Fight');

  readonly exactMatch: IsActiveMatchOptions = {
    paths: 'exact', queryParams: 'ignored', fragment: 'ignored', matrixParams: 'ignored',
  };
  readonly subsetMatch: IsActiveMatchOptions = {
    paths: 'subset', queryParams: 'ignored', fragment: 'ignored', matrixParams: 'ignored',
  };

  readonly navItems: NavItem[] = [
    { label: 'Dashboard',    rota: '/app/dashboard',    icone: 'home',           linkOptions: this.exactMatch },
    { label: 'Alunos',       rota: '/app/alunos',       icone: 'user-group',     linkOptions: this.subsetMatch },
    { label: 'Turmas',       rota: '/app/turmas',       icone: 'users-group',    linkOptions: this.subsetMatch },
    { label: 'Horários',     rota: '/app/horarios',     icone: 'clock',          linkOptions: this.subsetMatch },
    { label: 'Presenças',    rota: '/app/presencas',    icone: 'check-circle',   linkOptions: this.subsetMatch },
    { label: 'Graduação',    rota: '/app/graduacao',    icone: 'academic-cap',   linkOptions: this.subsetMatch },
    { label: 'Ranking',      rota: '/app/ranking',      icone: 'trophy',         linkOptions: this.subsetMatch },
    { label: 'Planos',       rota: '/app/planos',       icone: 'planos',         linkOptions: this.subsetMatch },
    { label: 'Financeiro',   rota: '/app/financeiro',   icone: 'currency',       linkOptions: this.subsetMatch },
    { label: 'Contratos',    rota: '/app/contratos',    icone: 'document-text',  linkOptions: this.subsetMatch },
    { label: 'Relatórios',   rota: '/app/relatorios',   icone: 'chart-bar',      linkOptions: this.subsetMatch },
  ];

  readonly navItemsConfig: NavItem[] = [
    { label: 'Catraca',      rota: '/app/catraca',      icone: 'lock-open',      linkOptions: this.subsetMatch },
    { label: 'Modalidades',  rota: '/app/modalidades',  icone: 'shield-check',   linkOptions: this.subsetMatch, roles: ['Admin'] },
    { label: 'Funcionários', rota: '/app/funcionarios', icone: 'identification', linkOptions: this.subsetMatch, roles: ['Admin'] },
    { label: 'Configurações',rota: '/app/configuracoes',icone: 'cog',            linkOptions: this.subsetMatch },
  ];

  ngOnInit(): void {
    this.academiaService.getCurrent().subscribe({
      next: res => { if (res.dados?.nome) this.academiaName.set(res.dados.nome); },
    });
  }

  get navItemsConfigVisiveis(): NavItem[] {
    const perfil = this.authService.currentUser()?.perfil ?? '';
    return this.navItemsConfig.filter(item => !item.roles || item.roles.includes(perfil));
  }

  brandMark(): string {
    return (this.academiaName() || 'A').charAt(0).toUpperCase();
  }

  sair(): void {
    this.authService.logout();
  }
}
